import { Component, Event, EventEmitter, h, Prop, State, Watch } from '@stencil/core';
import {
  buildTimePickerCalendarYear,
  CalYear,
  ITimePicker,
  SelectedItem,
  SelectedTime,
  SelectItem,
  TimePickerData
} from '@src/utils/mx-utils/calendar-service';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import isEqual from 'lodash.isequal';
import { KrogerDateBuilder } from 'kroger-date';

const DEFAULT_PICKER = -1;
const TIME_VIEW = { YEAR: 'year', QUARTER: 'quarter', PERIOD: 'period', WEEK: 'week', ALL: 'all' };
const CAL_TYPE = { FISCAL: 'fiscal', AD: 'ad' };
const SELECTED_ITEM = [
  { label: '--', value: DEFAULT_PICKER },
  { label: '1', value: 1 },
  { label: '2', value: 2 },
  { label: '3', value: 3 },
  { label: '4', value: 4 }];


@Component({
  tag: 'mx-time-picker',
  styleUrl: 'mx-time-picker.css',
  shadow: false
})
export class MxTimePicker {
  /** Sets the name of the time picker.   */
  @Prop({ reflect: true, attribute: 'name' }) readonly name: string;
  // in future this could be replaced with timePickerData props.
  // we can decide if we want that so we can use set value and get value
  /** Sets the value of the timepicker. */
  @Prop({ reflect: true, attribute: 'value', mutable: true }) value: ITimePicker;
  /** Sets time picker data to appropriate calendar dates (Fiscal: Sun-Sat, Ad: Wed-Tues). */
  @Prop({ mutable: true }) calType: 'fiscal' | 'ad' = 'fiscal';

  @Watch('calType')
  watchCalType(newVal) {
    this.calType = newVal;
  }

  /** Sets time picker to a start date on load. Format: YYYY/MM/DD. */
  @Prop() readonly initWithDate: string = '';
  /** Hides quarter dropdown. */
  @Prop() readonly hideQuarter: boolean = false;
  /** Hides period dropdown. */
  @Prop() readonly hidePeriod: boolean = false;
  /** Hides week dropdown. */
  @Prop() readonly hideWeek: boolean = false;
  /** Displays or hides the Ad and Fiscal Switcher. */
  @Prop() readonly showTypeSwitcher: boolean = false;
  /** Sets the number of years back in time year dropdown will display. */
  @Prop() readonly numPastYears: number = 2;
  /** Sets the number of years ahead in time year dropdown will display. */
  @Prop() readonly numFutureYears: number = 2;
  /** Disables all filter buttons except for specified time view. */
  @Prop() readonly restrictedFilterView: string = TIME_VIEW.ALL;
  /** Sets the date to the specificity level and does not allow time selection below that. */
  @Prop() readonly restrictDateSpecificity: string = TIME_VIEW.WEEK;
  /** Disables al the controls in the time picker */
  @Prop() readonly disabled: boolean = false;

  @Watch('restrictDateSpecificity')
  onRestrictDateSpecificityChange() {
    this.initiateTimePicker();
  }

  /** Sets the date to the specificity level on initialization. */
  @Prop() readonly initToSpecificity: string = TIME_VIEW.WEEK;
  /** Explicitly sets the value of Year, Quarter, Period, week dropdowns. Resets the picker if the values are passed as '-1' i.e.{year:-1, quarter:-1, period:-1, week: -1}. */
  @Prop({ mutable: true }) timePickerData: TimePickerData;
  /** Sets the minimum allowed date for time picker selection. */
  @Prop() readonly minDate: TimePickerData;
  /** Sets the maximum allowed date for time picker selection. */
  @Prop() readonly maxDate: TimePickerData;

  /** This event is emitted when the user change the date object {fiscalYear: number, period: number, quarter: number,week: number, timeStart: Date, timeEnd: Date} */
  @Event() pickerChange: EventEmitter<ITimePicker>;

  // eslint-disable-next-line max-len
  @State() _initWithDate: Date = isNullOrUndefinedOrEmptyString(this.initWithDate) ? new Date(Date.now()) : new Date(this.initWithDate);
  @State() referenceDateObj: Date = new Date(this._initWithDate);
  @State() filterDisable = { year: false, quarter: false, period: false, week: false };
  @State() pillFilters = { year: false, quarter: false, period: false, week: false };
  @State() hidePills = { year: false, quarter: this.hideQuarter, period: this.hidePeriod, week: this.hideWeek };
  @State() calData: CalYear;
  @State() dateOffset: number = 0;
  @State() dateSubject: TimePickerData;
  @State() selectedTime: SelectedTime = {
    selectedYear: {
      label: '-1',
      value: -1
    },
    selectedWeek: {
      label: '-1',
      value: -1
    },
    selectedPeriod: {
      label: '-1',
      value: -1
    },
    selectedQuarter: {
      label: '-1',
      value: -1
    }
  };
  @State() selectedItems: SelectedItem = { yearItems: [], quarterItems: SELECTED_ITEM, periodItems: [], weekItems: [] };

  componentWillLoad() {
    this.initiateTimePicker(true);
    this.setTimePickerData(false);
  }

  @Watch('initWithDate')
  onChangeInitWithDate() {
    this._initWithDate = isNullOrUndefinedOrEmptyString(this.initWithDate) ?
      new Date(Date.now()) :
      new Date(this.initWithDate);
    this.referenceDateObj = new Date(this._initWithDate);
    this.initiateTimePicker(true);
    this.setTimePickerData();
  }

  @Watch('timePickerData')
  onChangeTimePickerData(timePickerData: TimePickerData) {
    if (timePickerData == null) {
      this._initWithDate = new Date(Date.now());
    } else {
      const krogerDateBuilder: KrogerDateBuilder = new KrogerDateBuilder();
      krogerDateBuilder.year(timePickerData.year);
      krogerDateBuilder.period(timePickerData.period || 1);
      try {
        this._initWithDate = krogerDateBuilder.build().toDate();
      } catch (e) {
        console.warn('Invalid date due to minDate or maxDate', e);
      }
    }
    this.referenceDateObj = new Date(this._initWithDate);
    this.initiateTimePicker(true);
    this.setTimePickerData();
  }

  @Watch('dateSubject')
  watchDateSubject(newValue: TimePickerData) {
    this.setPillValues(newValue);
    this.generateQuarterItems();
    this.generatePeriodItems();
    this.generateWeekItems();
  }

  @Watch('minDate')
  watchMinDate() {
    this.selectedItems.yearItems = [];
    this.initiateTimePicker(false);
    this.setTimePickerData(false);
  }

  @Watch('maxDate')
  watchMaxDate() {
    this.selectedItems.yearItems = [];
    this.initiateTimePicker(false);
    this.setTimePickerData(false);
  }

  private getTimePickerData = (): ITimePicker => {
    const { timeStart, timeEnd } = this.getDateRangeStartAndEnd();
    this.updateDateRefObj(timeStart, timeEnd);
    const { selectedYear, selectedPeriod, selectedWeek, selectedQuarter } = this.selectedTime;
    const iTimePicker: ITimePicker = {
      calYear: selectedYear.value ? selectedYear.value : '',
      quarter: selectedQuarter.value === DEFAULT_PICKER ? '' : selectedQuarter.value,
      period: selectedPeriod.value === DEFAULT_PICKER ? '' : selectedPeriod.value,
      week: selectedWeek.value === DEFAULT_PICKER ? '' : selectedWeek.value,
      timeStart: timeStart || '',
      timeEnd: timeEnd || ''
    }; // custom for query-panel

    this.value = { ...iTimePicker, calType: this.calType === CAL_TYPE.AD ? 'ad' : 'fiscal' }; // custom for query-panel
    this.timePickerData = {
      year: selectedYear.value || -1,
      quarter: selectedQuarter.value,
      week: selectedWeek.value,
      period: selectedPeriod.value
    };
    return iTimePicker;
  };

  private isValidYear = (value) => {
    return value && this.selectedItems.yearItems.some((e) => e.value === value) &&
    this.selectedTime.selectedYear.value ? value : -1;
  };

  private isValidQuarter = (value) => {
    return value && this.selectedItems.quarterItems.some((e) => e.value === value) &&
    this.selectedTime.selectedYear.value ? value : -1;
  };

  private isValidPeriod = (value) => {
    return value && this.selectedItems.periodItems.some((e) => e.value === value) ? value : -1;
  };

  private isValidWeek = (value) => {
    return value && this.selectedItems.weekItems.some((e) => e.value === value) ? value : -1;
  };

  private initiateTimePicker(calledFromInit = false) {
    this.dateOffset = this.calType === CAL_TYPE.AD ? 3 : 0;
    this.hidePills = { year: false, quarter: this.hideQuarter, period: this.hidePeriod, week: this.hideWeek };
    this.setTimeView();
    this.toggleFilter(this.restrictDateSpecificity);
    this.buildCalendar(calledFromInit);
  }

  private setTimePickerData(emitPickerChangeEvent = true) {
    if (!isNullOrUndefined(this.timePickerData)) {

      const quarter = this.isValidQuarter(this.timePickerData.quarter);
      const quarterTimeStruct = this.updateQuarter({ value: quarter }, false);

      const period = this.isValidPeriod(this.timePickerData.period);
      const periodTimeStruct = this.updatePeriod({ value: period }, false);

      const week = this.isValidWeek(this.timePickerData.week);
      const weekTimeStruct = this.updateWeek({ value: week }, false);

      const year = this.isValidYear(this.timePickerData.year);
      const yearTimeStruct = this.updateYear({ value: year }, false);

      // eslint-disable-next-line max-len
      const timeStruct: TimePickerData = { ...quarterTimeStruct, ...periodTimeStruct, ...weekTimeStruct, ...yearTimeStruct };
      this.updateDate(timeStruct.week, timeStruct.period, timeStruct.quarter, true, emitPickerChangeEvent);

    }
  }

  private updateDateRefObj(timeStart: Date, timeEnd: Date) {
    if (!(this.referenceDateObj >= timeStart && this.referenceDateObj <= timeEnd)) {
      this.referenceDateObj = new Date(timeStart);
    }
  }

  private buildCalendar(calledFromInit = false) {
    this.dateOffset = this.calType === CAL_TYPE.AD ? 3 : 0;
    this.calData = buildTimePickerCalendarYear(this.referenceDateObj, this.dateOffset);
    if (this.selectedItems.yearItems.length <= 0) {
      this.selectedItems.yearItems = this.generateYearItems(this.calData.calYear);
    }
    this.generateQuarterItems();
    const foundWeek = this.calData.weeks.find((week) => this.referenceDateObj >= week.startDate &&
      this.referenceDateObj <= week.endDate);
    const foundPeriod = this.calData.periods.find((period) => period.period === foundWeek.period);
    const foundQuarter = this.calData.quarters.find((quarter) => quarter.quarter === foundPeriod.quarter);
    if (calledFromInit) {
      this.setSpecificity(foundWeek, foundPeriod, foundQuarter);
    } else {
      this.updateDate(foundWeek.week, foundPeriod.period, foundQuarter.quarter);
    }
  }

  // eslint-disable-next-line max-len
  private updateDate(foundWeek, foundPeriod, foundQuarter, isDateSubjectChange = true, emitPickerChangeEvent = true): TimePickerData {
    const dateSubject: TimePickerData = {
      year: this.calData.calYear,
      quarter: foundQuarter,
      period: foundPeriod,
      week: foundWeek
    };
    if (isDateSubjectChange) {
      if (dateSubject.year !== DEFAULT_PICKER && !isEqual(this.dateSubject, dateSubject)) {
        this.dateSubject = dateSubject;
        if (emitPickerChangeEvent) {
          this.pickerChange.emit(this.getTimePickerData());
        }
      }
    } else {
      this.setPillValues(dateSubject);
      this.generateQuarterItems();
      this.generatePeriodItems();
      this.generateWeekItems();
    }
    return dateSubject;
  }

  private setSpecificity(foundWeek, foundPeriod, foundQuarter) {
    const specificityActions = {
      week: () => this.updateDate(foundWeek.week, foundPeriod.period, foundQuarter.quarter, false),
      period: () => this.updateDate(DEFAULT_PICKER, foundPeriod.period, foundQuarter.quarter, false),
      quarter: () => this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, foundQuarter.quarter, false),
      year: () => this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, DEFAULT_PICKER, false)
    };

    specificityActions[this.initToSpecificity]();

    if (this.restrictDateSpecificity === TIME_VIEW.PERIOD) {
      this.hidePills[TIME_VIEW.WEEK] = true;
    }
    if (this.restrictDateSpecificity === TIME_VIEW.QUARTER) {
      this.hidePills[TIME_VIEW.WEEK] = true;
      this.hidePills[TIME_VIEW.PERIOD] = true;
    }
    if (this.restrictDateSpecificity === TIME_VIEW.YEAR) {
      this.hidePills[TIME_VIEW.WEEK] = true;
      this.hidePills[TIME_VIEW.PERIOD] = true;
      this.hidePills[TIME_VIEW.QUARTER] = true;
    }

    if (this.initToSpecificity !== this.restrictDateSpecificity && !this.hidePills[this.initToSpecificity]) {
      this.toggleFilter(this.initToSpecificity);
    }
  }

  private setTimeView() {
    if (this.restrictedFilterView !== TIME_VIEW.ALL) {
      Object.keys(this.filterDisable).forEach((key) => {
        this.filterDisable[key] = key !== this.restrictedFilterView;
      });
    }
  }

  private generateYearItems(year) {
    const years: SelectItem[] = [];
    const currentYear = year;
    let startYear = currentYear - this.numPastYears;
    let endYear = currentYear + this.numFutureYears;

    // Apply min/max date filtering for years
    if (this.minDate && this.minDate.year !== undefined && this.minDate.year !== -1) {
      startYear = Math.max(startYear, this.minDate.year);
    }
    if (this.maxDate && this.maxDate.year !== undefined && this.maxDate.year !== -1) {
      endYear = Math.min(endYear, this.maxDate.year);
    }

    for (let yr = startYear; yr <= endYear; yr++) {
      years.push({ label: yr.toString(), value: yr });
    }
    return years;
  }

  private generatePeriodItems() {
    let periods = this.calData.periods;

    if (!this.hideQuarter) {
      periods = periods.filter((period) => {
        return period.quarter === this.selectedTime.selectedQuarter.value;
      });
    }

    // Apply min/max date filtering for periods
    if (this.minDate || this.maxDate) {
      periods = periods.filter((period) => {
        const currentYear = this.calData.calYear;

        // Check minimum date
        if (this.minDate && this.minDate.year !== undefined && this.minDate.year !== -1) {
          if (currentYear < this.minDate.year) return false;
          if (currentYear === this.minDate.year && this.minDate.period !== undefined && this.minDate.period !== -1) {
            if (period.period < this.minDate.period) return false;
          }
        }

        // Check maximum date
        if (this.maxDate && this.maxDate.year !== undefined && this.maxDate.year !== -1) {
          if (currentYear > this.maxDate.year) return false;
          if (currentYear === this.maxDate.year && this.maxDate.period !== undefined && this.maxDate.period !== -1) {
            if (period.period > this.maxDate.period) return false;
          }
        }

        return true;
      });
    }

    this.selectedItems.periodItems = periods.map((period) => ({
      label: period.period.toString(),
      value: period.period
    }));

    this.selectedItems.periodItems.unshift({ label: '--', value: DEFAULT_PICKER });
  }

  private generateWeekItems() {
    let weeks = this.calData.weeks;

    if (!this.hidePeriod) {
      weeks = weeks.filter((week) => {
        return week.period === this.selectedTime.selectedPeriod.value;
      });
    }

    // Apply min/max date filtering for weeks
    if (this.minDate || this.maxDate) {
      weeks = weeks.filter((week) => {
        const currentYear = this.calData.calYear;

        // Check minimum date
        if (this.minDate && this.minDate.year !== undefined && this.minDate.year !== -1) {
          if (currentYear < this.minDate.year) return false;
          if (currentYear === this.minDate.year && this.minDate.week !== undefined && this.minDate.week !== -1) {
            if (week.week < this.minDate.week) return false;
          }
        }

        // Check maximum date
        if (this.maxDate && this.maxDate.year !== undefined && this.maxDate.year !== -1) {
          if (currentYear > this.maxDate.year) return false;
          if (currentYear === this.maxDate.year && this.maxDate.week !== undefined && this.maxDate.week !== -1) {
            if (week.week > this.maxDate.week) return false;
          }
        }

        return true;
      });
    }

    if (this.hidePeriod) {
      this.selectedItems.weekItems = weeks.map((week) => ({
        label: week.week.toString(),
        value: week.week
      }));
    } else {
      this.selectedItems.weekItems = weeks.map((week, index) => ({
        label: `${index + 1} (${week.week})`,
        value: week.week
      }));
    }

    this.selectedItems.weekItems.unshift({ label: '--', value: DEFAULT_PICKER });
  }

  private generateQuarterItems() {
    let quarterItems = [...SELECTED_ITEM];

    // Apply min/max date filtering for quarters
    if (this.minDate || this.maxDate) {
      quarterItems = quarterItems.filter((item) => {
        if (item.value === DEFAULT_PICKER) return true; // Always keep the default "--" option

        const quarterValue = item.value as number;
        const currentYear = this.calData.calYear;

        // Check minimum date
        if (this.minDate && this.minDate.year !== undefined && this.minDate.year !== -1) {
          if (currentYear < this.minDate.year) return false;
          if (currentYear === this.minDate.year && this.minDate.quarter !== undefined && this.minDate.quarter !== -1) {
            if (quarterValue < this.minDate.quarter) return false;
          }
        }

        // Check maximum date
        if (this.maxDate && this.maxDate.year !== undefined && this.maxDate.year !== -1) {
          if (currentYear > this.maxDate.year) return false;
          if (currentYear === this.maxDate.year && this.maxDate.quarter !== undefined && this.maxDate.quarter !== -1) {
            if (quarterValue > this.maxDate.quarter) return false;
          }
        }

        return true;
      });
    }

    this.selectedItems.quarterItems = quarterItems;
  }

  private setPillValues(dateStruct) {
    this.selectedTime = {
      selectedYear: { label: dateStruct.year, value: dateStruct.year },
      selectedQuarter: { label: dateStruct.quarter, value: dateStruct.quarter },
      selectedPeriod: { label: dateStruct.period, value: dateStruct.period },
      selectedWeek: { label: dateStruct.week, value: dateStruct.week }
    };
  }

  private toggleFilter(filterName: string) {
    Object.keys(this.pillFilters).forEach((key) => (this.pillFilters[key] = false));
    this.pillFilters[filterName] = !this.pillFilters[filterName];
  }

  private toggleFilterOnClick = (filterName) => (event) => {
    this.toggleFilter(filterName);
    const classList = [...event.detail.target.classList];

    if (classList.includes('year-filter')) {
      this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, DEFAULT_PICKER);
    }

    if (classList.includes('quarter-filter')) {
      this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, this.selectedTime.selectedQuarter.value);
    }

    if (classList.includes('period-filter')) {
      this.updateDate(DEFAULT_PICKER, this.selectedTime.selectedPeriod.value, this.selectedTime.selectedQuarter.value);
    }
  };

  private updateYear = (event, isDateSubjectChange = true): TimePickerData => {
    const value = this.getEventValue(event);
    this.calData = buildTimePickerCalendarYear(value, this.dateOffset);
    if (this.selectedTime.selectedQuarter.value === DEFAULT_PICKER &&
      this.selectedTime.selectedPeriod.value === DEFAULT_PICKER &&
      this.selectedTime.selectedWeek.value === DEFAULT_PICKER) {
      this.toggleFilter('year');
    }
    const weekVal = this.selectedTime.selectedWeek.value === 53 ? 52 : this.selectedTime.selectedWeek.value;
    // eslint-disable-next-line max-len
    return this.updateDate(weekVal, this.selectedTime.selectedPeriod.value, this.selectedTime.selectedQuarter.value, isDateSubjectChange);
  };

  private updateQuarter = (event, isDateSubjectChange = true): TimePickerData => {
    const quarter = this.getEventValue(event);
    this.toggleFilter('quarter');
    return this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, quarter, isDateSubjectChange);
  };

  private updatePeriod = (event, isDateSubjectChange = true): TimePickerData => {
    const period = this.getEventValue(event);
    if (period > 0) {
      this.toggleFilter('period');
      const quarterOfPeriod = this.calData.periods.find((pd) => pd.period === period).quarter;
      return this.updateDate(DEFAULT_PICKER, period, quarterOfPeriod, isDateSubjectChange);
    } else {
      // eslint-disable-next-line max-len
      return this.updateDate(DEFAULT_PICKER, DEFAULT_PICKER, this.selectedTime.selectedQuarter.value, isDateSubjectChange);
    }
  };

  private updateWeek = (event, isDateSubjectChange = true): TimePickerData => {
    const week = this.getEventValue(event);
    if (week > 0) {
      this.toggleFilter('week');
      const periodOfWk = this.calData.weeks.find((wk) => wk.week === week).period;
      const quarterOfPeriod = this.calData.periods.find((pd) => pd.period === periodOfWk).quarter;
      return this.updateDate(week, periodOfWk, quarterOfPeriod, isDateSubjectChange);
    } else {
      // eslint-disable-next-line max-len
      return this.updateDate(DEFAULT_PICKER, this.selectedTime.selectedPeriod.value, this.selectedTime.selectedQuarter.value, isDateSubjectChange);
    }
  };

  private getDateRangeStartAndEnd() {
    const dateRange = { timeStart: this.calData.startDate, timeEnd: this.calData.endDate };
    const { selectedWeek, selectedPeriod, selectedQuarter } = this.selectedTime;

    if (selectedWeek.value !== DEFAULT_PICKER) {
      dateRange.timeStart = this.calData.weeks[selectedWeek.value - 1].startDate;
      dateRange.timeEnd = this.calData.weeks[selectedWeek.value - 1].endDate;
      return dateRange;
    }

    if (selectedPeriod.value !== DEFAULT_PICKER) {
      dateRange.timeStart = this.calData.periods[selectedPeriod.value - 1].startDate;
      dateRange.timeEnd = this.calData.periods[selectedPeriod.value - 1].endDate;
      return dateRange;
    }

    if (selectedQuarter.value !== DEFAULT_PICKER) {
      dateRange.timeStart = this.calData.quarters[selectedQuarter.value - 1].startDate;
      dateRange.timeEnd = this.calData.quarters[selectedQuarter.value - 1].endDate;
      return dateRange;
    }
    return dateRange;
  }

  private updateCal = ({ detail: { event, type } }) => {
    event.stopPropagation();
    this.calType = type;
    this.buildCalendar();
  };

  private getEventValue(event) {
    return event.detail ? event.detail.value : event.value;
  }

  render() {
    return (
      <div class='mx-component-container' role='region' aria-label='timeframe picker'>
        {this.showTypeSwitcher && (
          <mx-time-switcher
            disabled={this.disabled}
            onUpdateCal={this.updateCal}
            cal-type={this.calType}></mx-time-switcher>
        )}

        <div class='mx-picker-container'>
          <mx-picker-pill
            filter-disable={this.disabled || this.filterDisable.year}
            dropdown-disable={this.disabled}
            is-active={this.pillFilters.year}
            items={this.selectedItems.yearItems}
            selectedItem={this.selectedTime.selectedYear}
            onUpdateItem={this.updateYear}
            onToggleFilter={this.toggleFilterOnClick('year')}
            pill-label='Y'
            filtersType='year'></mx-picker-pill>

          <div class='mx-decorative-line bg-neutral-least-subtle'></div>

          {!this.hidePills.quarter && (
            <mx-picker-pill
              filter-disable={
                this.disabled || this.filterDisable.quarter || this.selectedTime.selectedQuarter.value === -1
              }
              dropdown-disable={this.disabled || !this.selectedTime.selectedYear.value}
              is-active={this.pillFilters.quarter}
              items={this.selectedItems.quarterItems}
              selectedItem={this.selectedTime.selectedQuarter}
              onUpdateItem={this.updateQuarter}
              onToggleFilter={this.toggleFilterOnClick('quarter')}
              pill-label='Q'
              filtersType='quarter'></mx-picker-pill>
          )}

          {!this.hidePills.period && (
            <mx-picker-pill
              filter-disable={
                this.disabled || this.filterDisable.period || this.selectedTime.selectedPeriod.value === -1
              }
              dropdown-disable={
                this.disabled || (this.selectedTime.selectedQuarter.value === -1 && !this.hidePills.quarter)
              }
              is-active={this.pillFilters.period}
              items={this.selectedItems.periodItems}
              selectedItem={this.selectedTime.selectedPeriod}
              onUpdateItem={this.updatePeriod}
              onToggleFilter={this.toggleFilterOnClick('period')}
              pill-label='P'
              filtersType='period'></mx-picker-pill>
          )}

          {!this.hidePills.week && (
            <mx-picker-pill
              filter-disable={
                this.disabled || this.filterDisable.week || this.selectedTime.selectedWeek.value === -1
              }
              dropdown-disable={
                this.disabled || (this.selectedTime.selectedPeriod.value === -1 && !this.hidePills.period)
              }
              is-active={this.pillFilters.week}
              items={this.selectedItems.weekItems}
              selectedItem={this.selectedTime.selectedWeek}
              onUpdateItem={this.updateWeek}
              onToggleFilter={this.toggleFilterOnClick('week')}
              pill-label='W'
              filtersType='week'></mx-picker-pill>
          )}
        </div>
      </div>
    );
  }
}
